"use client";

/**
 * 時間割 / 授業管理（中学・高校の教務向け）— cold-start evaluation build of
 * @gunjo/ui@0.0.1-alpha.2.
 *
 * HEADLINE GAP (confirmed against the package source AND gunjo.jp/docs):
 * the library ships NO timetable / scheduler / week-view / time-grid / 2D
 * content-grid primitive. `Calendar` is a react-day-picker date PICKER;
 * `SegmentTimelineCard` is a single horizontal value-timeline; `HeatmapChart`
 * is numeric x/y cells; `Grid` is a pure CSS-grid layout helper. So the core
 * 時限×曜日 grid (./TimetableGrid) is hand-rolled from div + role="grid" + the
 * tone tokens. The library DOES contribute everything around it: Card, Sheet,
 * Select, Button, Badge, Alert, Banner, Meter, Statistic, Separator, Tabs/
 * ToggleGroup, Tooltip, Icon, plus the success/warning/destructive/info tone
 * scale used for status + conflict styling.
 */

import * as React from "react";
import {
  Card,
  CardContent,
  Statistic,
  Badge,
  Button,
  Banner,
  Alert,
  AlertTitle,
  AlertDescription,
  Select,
  ToggleGroup,
  ToggleGroupItem,
  Separator,
  Icon,
} from "@gunjo/ui";
import {
  IconAlertTriangle,
  IconCircleCheck,
  IconLayoutGrid,
  IconUser,
  IconDoor,
  IconChevronLeft,
  IconChevronRight,
  IconCalendarOff,
  IconCalendarPlus,
} from "@tabler/icons-react";
import {
  INITIAL_BLOCKS,
  DAYS,
  PERIODS,
  TEACHERS,
  ROOMS,
  computeConflicts,
  computeTeacherLoads,
  isSlotInSession,
  teacherById,
  roomById,
  type ClassBlock,
  type DayKey,
} from "./data";
import { TimetableGrid } from "./TimetableGrid";
import { TeacherLoadPanel } from "./TeacherLoadPanel";
import { CellEditorSheet, type CellEditorTarget } from "./CellEditorSheet";

type ViewMode = "class" | "teacher" | "room";

const slotKey = (period: number, day: DayKey) => `${period}-${day}`;

export default function ClassTimetablePage() {
  const [blocks, setBlocks] = React.useState<Record<string, ClassBlock>>(
    () => ({ ...INITIAL_BLOCKS })
  );
  const [view, setView] = React.useState<ViewMode>("class");
  const [focusTeacher, setFocusTeacher] = React.useState<string>(TEACHERS[0].id);
  const [focusRoom, setFocusRoom] = React.useState<string>(ROOMS[0].id);
  const [editTarget, setEditTarget] = React.useState<CellEditorTarget | null>(null);

  const conflicts = React.useMemo(() => computeConflicts(blocks), [blocks]);
  const loads = React.useMemo(() => computeTeacherLoads(blocks), [blocks]);

  // 集計
  const totalSlots = React.useMemo(
    () =>
      PERIODS.reduce(
        (acc, p) => acc + DAYS.filter((d) => isSlotInSession(p.period, d.key)).length,
        0
      ),
    []
  );
  const filledCount = Object.keys(blocks).length;
  const cancelledCount = Object.values(blocks).filter((b) => b.status === "cancelled").length;
  const makeupCount = Object.values(blocks).filter((b) => b.status === "makeup").length;
  const conflictCellCount = conflicts.size;
  const overloadCount = loads.filter((l) => l.over).length;

  const highlight =
    view === "teacher"
      ? ({ kind: "teacher", id: focusTeacher } as const)
      : view === "room"
      ? ({ kind: "room", id: focusRoom } as const)
      : null;

  const openEditor = (period: number, day: DayKey) => {
    const d = DAYS.find((x) => x.key === day)!;
    const p = PERIODS.find((x) => x.period === period)!;
    setEditTarget({
      period,
      day,
      dayLong: d.long,
      periodLabel: p.label,
      block: blocks[slotKey(period, day)] ?? null,
    });
  };

  const saveBlock = (next: ClassBlock) => {
    setBlocks((prev) => ({ ...prev, [slotKey(next.period, next.day)]: next }));
    setEditTarget(null);
  };

  const clearBlock = () => {
    if (!editTarget) return;
    setBlocks((prev) => {
      const copy = { ...prev };
      delete copy[slotKey(editTarget.period, editTarget.day)];
      return copy;
    });
    setEditTarget(null);
  };

  // 競合の人間可読リスト（バナーの下に展開）
  const conflictList = React.useMemo(() => {
    const out: { key: string; label: string }[] = [];
    for (const [key, list] of conflicts) {
      const [period, day] = key.split("-") as [string, DayKey];
      const d = DAYS.find((x) => x.key === day)!;
      for (const c of list) {
        out.push({
          key: `${key}-${c.kind}-${c.withLabel}`,
          label: `${d.long}${period}限：${c.kind === "teacher" ? "教員" : "教室"}「${c.resourceLabel}」が ${c.withLabel} と重複`,
        });
      }
    }
    return out;
  }, [conflicts]);

  return (
    <main className="mx-auto w-full max-w-7xl px-4 py-6 sm:px-6 lg:py-8">
      {/* ヘッダ */}
      <header className="mb-6 flex flex-col gap-4">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div>
            <p className="text-xs font-medium text-muted-foreground">時間割管理 / 教務</p>
            <h1 className="text-2xl font-bold tracking-tight">2年A組 週間時間割</h1>
            <p className="mt-1 text-sm text-muted-foreground">
              2025年度 1学期 ／ 担任：鈴木 美和（英語） ／ 在籍 34名
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm" aria-label="前の週">
              <Icon icon={IconChevronLeft} size="sm" decorative />
              前週
            </Button>
            <Badge variant="outline" className="h-8 px-3">
              第 8 週（5/19〜5/24）
            </Badge>
            <Button variant="outline" size="sm" aria-label="次の週">
              次週
              <Icon icon={IconChevronRight} size="sm" decorative />
            </Button>
          </div>
        </div>

        {/* サマリ統計 */}
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5">
          <Statistic
            label="割当済みコマ"
            value={`${filledCount} / ${totalSlots}`}
            hint="空きを除く実授業数"
          />
          <Statistic
            label="競合"
            value={`${conflictCellCount} 件`}
            trend={conflictCellCount > 0 ? "up" : "flat"}
            tone={conflictCellCount > 0 ? "negative" : "neutral"}
            change={conflictCellCount > 0 ? "要対応" : "なし"}
          />
          <Statistic
            label="休講"
            value={`${cancelledCount} 件`}
            hint="今週分"
          />
          <Statistic
            label="補講"
            value={`${makeupCount} 件`}
            hint="今週分"
          />
          <Statistic
            label="過負荷の教員"
            value={`${overloadCount} 名`}
            trend={overloadCount > 0 ? "up" : "flat"}
            tone={overloadCount > 0 ? "negative" : "neutral"}
            change={overloadCount > 0 ? "上限超過" : "上限内"}
          />
        </div>
      </header>

      {/* 競合バナー（色だけに頼らない：アイコン＋見出し＋件数＋詳細リスト） */}
      {conflictCellCount > 0 ? (
        <Alert variant="destructive" className="mb-5" aria-live="polite">
          <IconAlertTriangle aria-hidden />
          <AlertTitle>
            ダブルブッキングが {conflictCellCount} 箇所あります
          </AlertTitle>
          <AlertDescription>
            <ul className="mt-1 flex list-disc flex-col gap-1 pl-4">
              {conflictList.map((c) => (
                <li key={c.key}>{c.label}</li>
              ))}
            </ul>
            <p className="mt-2 text-xs">
              該当セルには <span className="font-semibold">「競合」ラベルと太い枠線</span>が付いています。セルを開いて担当・教室を変更してください。
            </p>
          </AlertDescription>
        </Alert>
      ) : (
        <Banner variant="success" className="mb-5" icon={<Icon icon={IconCircleCheck} size="sm" decorative />}>
          競合はありません。時間割は確定可能です。
        </Banner>
      )}

      {/* ビュー切替 + 絞り込み */}
      <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
        <div className="flex flex-col gap-1.5">
          <span id="view-label" className="text-xs font-medium text-muted-foreground">
            表示
          </span>
          <ToggleGroup
            type="single"
            value={view}
            onValueChange={(v) => v && setView(v as ViewMode)}
            disallowEmpty
            variant="outline"
            aria-labelledby="view-label"
          >
            <ToggleGroupItem value="class" aria-label="クラスビュー">
              <Icon icon={IconLayoutGrid} size="sm" decorative />
              クラス
            </ToggleGroupItem>
            <ToggleGroupItem value="teacher" aria-label="教員ビュー">
              <Icon icon={IconUser} size="sm" decorative />
              教員
            </ToggleGroupItem>
            <ToggleGroupItem value="room" aria-label="教室ビュー">
              <Icon icon={IconDoor} size="sm" decorative />
              教室
            </ToggleGroupItem>
          </ToggleGroup>
        </div>

        {view === "teacher" && (
          <div className="w-full sm:w-64">
            <Select
              label="教員を選択"
              value={focusTeacher}
              onChange={(e) => setFocusTeacher(e.target.value)}
            >
              {TEACHERS.map((t) => (
                <option key={t.id} value={t.id}>
                  {t.name}（{t.subject}）
                </option>
              ))}
            </Select>
          </div>
        )}
        {view === "room" && (
          <div className="w-full sm:w-64">
            <Select
              label="教室を選択"
              value={focusRoom}
              onChange={(e) => setFocusRoom(e.target.value)}
            >
              {ROOMS.map((r) => (
                <option key={r.id} value={r.id}>
                  {r.name}（{r.kind}）
                </option>
              ))}
            </Select>
          </div>
        )}
      </div>

      {/* 教員/教室ビューの説明 */}
      {view !== "class" && (
        <p className="mb-3 text-sm text-muted-foreground">
          {view === "teacher" ? (
            <>
              <span className="font-medium text-foreground">
                {teacherById(focusTeacher)?.name}
              </span>{" "}
              先生の担当コマを強調表示しています。それ以外は薄く表示されます。
            </>
          ) : (
            <>
              <span className="font-medium text-foreground">{roomById(focusRoom)?.name}</span>{" "}
              を使用するコマを強調表示しています。それ以外は薄く表示されます。
            </>
          )}
        </p>
      )}

      {/* 本体：グリッド + サイド（担当コマ数） */}
      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,1fr)_320px]">
        <Card className="min-w-0">
          <CardContent className="min-w-0 p-3 sm:p-4">
            <TimetableGrid
              blocks={blocks}
              conflicts={conflicts}
              highlight={highlight}
              onEditCell={openEditor}
            />
          </CardContent>
        </Card>

        <aside className="flex flex-col gap-4">
          <TeacherLoadPanel
            loads={loads}
            activeTeacherId={view === "teacher" ? focusTeacher : null}
            onSelectTeacher={(id) => {
              setFocusTeacher(id);
              setView("teacher");
            }}
          />

          {/* 休講・補講の一覧 */}
          <Card>
            <CardContent className="flex flex-col gap-3 p-4">
              <h2 className="text-base font-semibold">休講・補講</h2>
              <Separator />
              <ul className="flex flex-col gap-2">
                {Object.values(blocks)
                  .filter((b) => b.status !== "scheduled")
                  .sort((a, b) => a.day.localeCompare(b.day) || a.period - b.period)
                  .map((b) => {
                    const d = DAYS.find((x) => x.key === b.day)!;
                    return (
                      <li
                        key={`${b.period}-${b.day}`}
                        className="flex items-start gap-2 rounded-md border border-border p-2 text-sm"
                      >
                        <Icon
                          icon={b.status === "cancelled" ? IconCalendarOff : IconCalendarPlus}
                          size="sm"
                          decorative
                          className={
                            b.status === "cancelled" ? "mt-0.5 text-destructive" : "mt-0.5 text-info"
                          }
                        />
                        <div className="flex flex-col">
                          <span className="font-medium">
                            {d.long}
                            {b.period}限 {b.subject}{" "}
                            {b.status === "cancelled" ? (
                              <Badge variant="destructive">休講</Badge>
                            ) : (
                              <Badge variant="info">補講</Badge>
                            )}
                          </span>
                          <span className="text-xs text-muted-foreground">
                            {teacherById(b.teacherId)?.name} ／ {roomById(b.roomId)?.name}
                          </span>
                          {b.note && (
                            <span className="mt-0.5 text-xs text-muted-foreground">
                              {b.note}
                            </span>
                          )}
                        </div>
                      </li>
                    );
                  })}
                {Object.values(blocks).every((b) => b.status === "scheduled") && (
                  <li className="text-sm text-muted-foreground">
                    今週の休講・補講はありません。
                  </li>
                )}
              </ul>
            </CardContent>
          </Card>
        </aside>
      </div>

      <CellEditorSheet
        target={editTarget}
        blocks={blocks}
        onClose={() => setEditTarget(null)}
        onSave={saveBlock}
        onClear={clearBlock}
      />
    </main>
  );
}

"use client";

import * as React from "react";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  Select,
  Button,
  Alert,
  AlertTitle,
  AlertDescription,
  Badge,
  Separator,
  Icon,
} from "@gunjo/ui";
import {
  IconAlertTriangle,
  IconUser,
  IconDoor,
  IconCalendarOff,
  IconCalendarPlus,
} from "@tabler/icons-react";
import {
  type ClassBlock,
  type ClassStatus,
  type DayKey,
  type Subject,
  SUBJECTS,
  TEACHERS,
  ROOMS,
  OTHER_BOOKINGS,
  teacherById,
  roomById,
} from "./data";

export interface CellEditorTarget {
  period: number;
  day: DayKey;
  dayLong: string;
  periodLabel: string;
  block: ClassBlock | null;
}

interface CellEditorSheetProps {
  target: CellEditorTarget | null;
  /** すべての現行ブロック（編集中スロット以外の競合プレビューに使う）。 */
  blocks: Record<string, ClassBlock>;
  onClose: () => void;
  onSave: (next: ClassBlock) => void;
  onClear: () => void;
}

interface Draft {
  subject: Subject;
  teacherId: string;
  roomId: string;
  status: ClassStatus;
  note: string;
}

/** ドラフトに対するライブ競合プレビュー（他クラス予約との突き合わせ）。 */
function previewConflicts(
  period: number,
  day: DayKey,
  teacherId: string,
  roomId: string,
  status: ClassStatus
): { kind: "teacher" | "room"; label: string; withLabel: string }[] {
  if (status === "cancelled") return [];
  const out: { kind: "teacher" | "room"; label: string; withLabel: string }[] = [];
  for (const ob of OTHER_BOOKINGS) {
    if (ob.period !== period || ob.day !== day) continue;
    if (ob.teacherId && ob.teacherId === teacherId) {
      out.push({
        kind: "teacher",
        label: teacherById(teacherId)?.name ?? "教員",
        withLabel: ob.where,
      });
    }
    if (ob.roomId && ob.roomId === roomId) {
      out.push({
        kind: "room",
        label: roomById(roomId)?.name ?? "教室",
        withLabel: ob.where,
      });
    }
  }
  return out;
}

export function CellEditorSheet({
  target,
  onClose,
  onSave,
  onClear,
}: CellEditorSheetProps) {
  const [draft, setDraft] = React.useState<Draft | null>(null);

  React.useEffect(() => {
    if (!target) {
      setDraft(null);
      return;
    }
    const b = target.block;
    setDraft({
      subject: b?.subject ?? "国語",
      teacherId: b?.teacherId ?? TEACHERS[0].id,
      roomId: b?.roomId ?? ROOMS[0].id,
      status: b?.status ?? "scheduled",
      note: b?.note ?? "",
    });
  }, [target]);

  const open = Boolean(target);

  const conflicts = React.useMemo(() => {
    if (!target || !draft) return [];
    return previewConflicts(
      target.period,
      target.day,
      draft.teacherId,
      draft.roomId,
      draft.status
    );
  }, [target, draft]);

  if (!target || !draft) {
    return (
      <Sheet open={open} onOpenChange={(o) => !o && onClose()}>
        <SheetContent side="right" />
      </Sheet>
    );
  }

  const set = <K extends keyof Draft>(key: K, value: Draft[K]) =>
    setDraft((d) => (d ? { ...d, [key]: value } : d));

  const handleSave = () => {
    onSave({
      period: target.period,
      day: target.day,
      subject: draft.subject,
      teacherId: draft.teacherId,
      roomId: draft.roomId,
      status: draft.status,
      note: draft.note.trim() || undefined,
    });
  };

  const statusOrder: ClassStatus[] = ["scheduled", "cancelled", "makeup"];
  const statusLabel: Record<ClassStatus, string> = {
    scheduled: "通常授業",
    cancelled: "休講",
    makeup: "補講",
  };

  return (
    <Sheet open={open} onOpenChange={(o) => !o && onClose()}>
      <SheetContent side="right" className="flex w-full flex-col gap-0 overflow-y-auto sm:max-w-md">
        <SheetHeader className="text-left">
          <SheetTitle>
            {target.dayLong}・{target.periodLabel} のコマを編集
          </SheetTitle>
          <SheetDescription>
            2年A組 — 科目・担当教員・教室を割り当てます。保存すると競合が再判定されます。
          </SheetDescription>
        </SheetHeader>

        <div className="mt-4 flex flex-col gap-4">
          {/* 状態（通常 / 休講 / 補講） */}
          <fieldset className="flex flex-col gap-2">
            <legend className="text-sm font-medium text-foreground">区分</legend>
            <div role="radiogroup" aria-label="授業区分" className="flex gap-2">
              {statusOrder.map((s) => {
                const active = draft.status === s;
                return (
                  <Button
                    key={s}
                    type="button"
                    role="radio"
                    aria-checked={active}
                    variant={
                      active
                        ? s === "cancelled"
                          ? "destructive"
                          : s === "makeup"
                          ? "info"
                          : "primary"
                        : "outline"
                    }
                    size="sm"
                    onClick={() => set("status", s)}
                  >
                    {s === "cancelled" ? (
                      <Icon icon={IconCalendarOff} size="sm" decorative />
                    ) : s === "makeup" ? (
                      <Icon icon={IconCalendarPlus} size="sm" decorative />
                    ) : null}
                    {statusLabel[s]}
                  </Button>
                );
              })}
            </div>
          </fieldset>

          <Separator />

          <Select
            label="科目"
            value={draft.subject}
            onChange={(e) => set("subject", e.target.value as Subject)}
            disabled={draft.status === "cancelled" && !target.block}
          >
            {SUBJECTS.map((s) => (
              <option key={s} value={s}>
                {s}
              </option>
            ))}
          </Select>

          <Select
            label="担当教員"
            description="同じ時限に別クラスを担当している場合は競合として警告します。"
            value={draft.teacherId}
            onChange={(e) => set("teacherId", e.target.value)}
          >
            {TEACHERS.map((t) => (
              <option key={t.id} value={t.id}>
                {t.name}（{t.subject}）
              </option>
            ))}
          </Select>

          <Select
            label="教室"
            value={draft.roomId}
            onChange={(e) => set("roomId", e.target.value)}
          >
            {ROOMS.map((r) => (
              <option key={r.id} value={r.id}>
                {r.name}
              </option>
            ))}
          </Select>

          {(draft.status === "cancelled" || draft.status === "makeup") && (
            <div className="flex flex-col gap-1.5">
              <label
                htmlFor="cell-note"
                className="text-sm font-medium leading-none text-foreground"
              >
                {draft.status === "cancelled" ? "休講理由" : "補講メモ"}
              </label>
              <textarea
                id="cell-note"
                value={draft.note}
                onChange={(e) => set("note", e.target.value)}
                rows={2}
                placeholder={
                  draft.status === "cancelled"
                    ? "例）担当者出張のため"
                    : "例）5/12 休講分の振替"
                }
                className="w-full rounded-lg border border-input bg-transparent px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-ring"
              />
            </div>
          )}

          {/* ライブ競合プレビュー — 色だけに依存しない（アイコン＋見出し＋本文） */}
          {conflicts.length > 0 && (
            <Alert variant="destructive" aria-live="polite">
              <IconAlertTriangle aria-hidden />
              <AlertTitle>このまま保存すると競合します（{conflicts.length}件）</AlertTitle>
              <AlertDescription>
                <ul className="mt-1 flex flex-col gap-1">
                  {conflicts.map((c, i) => (
                    <li key={i} className="flex items-start gap-1.5">
                      <Icon
                        icon={c.kind === "teacher" ? IconUser : IconDoor}
                        size="sm"
                        decorative
                        className="mt-0.5 shrink-0"
                      />
                      <span>
                        <span className="font-medium">{c.label}</span> は同じ時限に{" "}
                        <span className="font-medium">{c.withLabel}</span> でも
                        {c.kind === "teacher" ? "授業を担当" : "使用"}予定です。
                      </span>
                    </li>
                  ))}
                </ul>
              </AlertDescription>
            </Alert>
          )}
        </div>

        <SheetFooter className="mt-6 flex-col gap-2 sm:flex-col">
          <Button type="button" variant="primary" className="w-full" onClick={handleSave}>
            このコマを保存
          </Button>
          {target.block && (
            <Button
              type="button"
              variant="outline"
              className="w-full"
              onClick={onClear}
            >
              コマを空きにする
            </Button>
          )}
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}

/**
 * 時間割 / 授業管理 — domain model, seed data, and conflict logic.
 *
 * Built on @gunjo/ui@0.0.1-alpha.2. No scheduler/time-grid primitive exists in
 * the library (Calendar is a react-day-picker date PICKER, SegmentTimelineCard
 * is a single horizontal value-timeline, HeatmapChart is numeric x/y cells), so
 * the weekly grid is composed from layout/display primitives. This module holds
 * the data + the conflict/load computation that the view layer renders.
 */

export type DayKey = "mon" | "tue" | "wed" | "thu" | "fri" | "sat";

export interface DayDef {
  key: DayKey;
  label: string; // 月
  long: string; // 月曜
}

