// ---- 競合検出 ------------------------------------------------------------

export type ConflictKind = "teacher" | "room";

export interface Conflict {
  kind: ConflictKind;
  period: number;
  day: DayKey;
  /** 競合している相手（他クラス名など）。 */
  withLabel: string;
  /** 競合対象の名前（先生名 / 教室名）。 */
  resourceLabel: string;
}

export function teacherById(id: string): Teacher | undefined {
  return TEACHERS.find((t) => t.id === id);
}
export function roomById(id: string): Room | undefined {
  return ROOMS.find((r) => r.id === id);
}

/**
 * 全セルの競合を計算する。判定対象は status==="scheduled"|"makeup"（休講は除外）。
 * 1) 同一クラス内で同じ時限に同じ教員/教室が複数（理屈上はクラス時間割では起きにくいが防御的に）
 * 2) OTHER_BOOKINGS との突き合わせ（別クラスとのダブルブッキング）
 * キーは "period-day"。1セルに複数競合が乗ることもある。
 */
export function computeConflicts(
  blocks: Record<string, ClassBlock>
): Map<string, Conflict[]> {
  const result = new Map<string, Conflict[]>();
  const active = Object.values(blocks).filter((b) => b.status !== "cancelled");

  const push = (key: string, c: Conflict) => {
    const arr = result.get(key) ?? [];
    arr.push(c);
    result.set(key, arr);
  };

  // 1) クラス内の重複（同 period-day に複数ブロックが入ることは構造上ないが、
  //    同一 period で別 day の同教員などは競合ではない＝同時刻の定義は period+day）。
  //    ここでは同 period+day の教員/教室二重を、active 同士で素直に検出。
  const bySlotTeacher = new Map<string, ClassBlock[]>();
  const bySlotRoom = new Map<string, ClassBlock[]>();
  for (const b of active) {
    const slot = k(b.period, b.day);
    bySlotTeacher.set(`${slot}|${b.teacherId}`, [
      ...(bySlotTeacher.get(`${slot}|${b.teacherId}`) ?? []),
      b,
    ]);
    bySlotRoom.set(`${slot}|${b.roomId}`, [
      ...(bySlotRoom.get(`${slot}|${b.roomId}`) ?? []),
      b,
    ]);
  }

  // 2) OTHER_BOOKINGS と突き合わせ
  for (const b of active) {
    const slot = k(b.period, b.day);
    for (const ob of OTHER_BOOKINGS) {
      if (ob.period !== b.period || ob.day !== b.day) continue;
      if (ob.teacherId && ob.teacherId === b.teacherId) {
        push(slot, {
          kind: "teacher",
          period: b.period,
          day: b.day,
          withLabel: ob.where,
          resourceLabel: teacherById(b.teacherId)?.name ?? "教員",
        });
      }
      if (ob.roomId && ob.roomId === b.roomId) {
        push(slot, {
          kind: "room",
          period: b.period,
          day: b.day,
          withLabel: ob.where,
          resourceLabel: roomById(b.roomId)?.name ?? "教室",
        });
      }
    }
  }

  return result;
}

