export interface TeacherLoad {
  teacher: Teacher;
  /** このクラスで担当する週コマ数（休講は除外）。 */
  count: number;
  /** maxLoad に対する過負荷判定。 */
  over: boolean;
}

export function computeTeacherLoads(
  blocks: Record<string, ClassBlock>
): TeacherLoad[] {
  const counts = new Map<string, number>();
  for (const b of Object.values(blocks)) {
    if (b.status === "cancelled") continue;
    counts.set(b.teacherId, (counts.get(b.teacherId) ?? 0) + 1);
  }
  return TEACHERS.filter((t) => counts.has(t.id))
    .map((teacher) => {
      const count = counts.get(teacher.id) ?? 0;
      return { teacher, count, over: count > teacher.maxLoad };
    })
    .sort((a, b) => b.count - a.count);
}

