              const key = slotKey(p.period, d.key);
              const block = blocks[key];
              const inSession = isSlotInSession(p.period, d.key);
              const cellConflicts = conflicts.get(key) ?? [];
              const hasConflict = cellConflicts.length > 0;
              const dimmed = !matchesHighlight(block);

              // セルのアクセシブル名 — 読み上げで「何が・誰が・どこで・状態」が一度に分かる。
              const a11yParts: string[] = [`${d.long} ${p.label}`];
              if (!inSession) a11yParts.push("授業なし");
              else if (!block) a11yParts.push("空き時間。クリックで割り当て");
              else {
                a11yParts.push(block.subject);
                a11yParts.push(teacherById(block.teacherId)?.name ?? "");
                a11yParts.push(roomById(block.roomId)?.name ?? "");
                if (block.status === "cancelled") a11yParts.push("休講");
                if (block.status === "makeup") a11yParts.push("補講");
                if (hasConflict)
                  a11yParts.push(
                    `競合あり。${cellConflicts
                      .map(
                        (c) =>
                          `${c.kind === "teacher" ? "教員" : "教室"}${c.resourceLabel}が${c.withLabel}と重複`
                      )
                      .join("、")}`
                  );
              }

              if (!inSession) {
                return (
                  <div
                    key={key}
                    role="gridcell"
                    aria-colindex={di + 2}
                    aria-rowindex={pi + 2}
                    aria-label={`${d.long} ${p.label} 授業なし`}
                    className="flex items-center justify-center rounded-md border border-dashed border-border bg-muted/30 px-2 py-3 text-[11px] text-muted-foreground"
                  >
                    授業なし
                  </div>
                );
              }

              return (
                <div
                  key={key}
                  role="gridcell"
                  aria-colindex={di + 2}
                  aria-rowindex={pi + 2}
                  className="min-h-[96px]"
                >
                  <button
                    type="button"
                    onClick={() => onEditCell(p.period, d.key)}
                    aria-label={a11yParts.filter(Boolean).join("、")}
                    className={cn(
                      "group relative flex h-full w-full flex-col rounded-md border p-2 text-left transition-colors",
                      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
                      "hover:border-primary/60 hover:shadow-sm",
                      block ? STATUS_CELL_CLASS[block.status] : "border-dashed border-border bg-card",
                      hasConflict && "ring-2 ring-destructive ring-offset-1"
                    )}
                  >
                    {block ? (
                      <CellInner block={block} hasConflict={hasConflict} dimmed={dimmed} />
                    ) : (
                      <span className="flex h-full min-h-[72px] items-center justify-center gap-1 text-xs text-muted-foreground group-hover:text-foreground">
                        <Icon icon={IconPlus} size="sm" decorative />
                        空き
                      </span>
                    )}
                  </button>
                </div>
              );
            })}
          </div>
        ))}
      </div>

      {/* 凡例 — 状態が色だけで区別されないことを明示 */}
      <div className="mt-3 flex flex-wrap items-center gap-x-4 gap-y-2 text-xs text-muted-foreground">
        <span className="inline-flex items-center gap-1">
          <Icon icon={IconAlertTriangle} size="xs" decorative className="text-destructive" />
          競合（二重予約）
        </span>
        <span className="inline-flex items-center gap-1">
          <Icon icon={IconCalendarOff} size="xs" decorative className="text-destructive" />
          休講
        </span>
        <span className="inline-flex items-center gap-1">
          <Icon icon={IconCalendarPlus} size="xs" decorative className="text-info" />
          補講
        </span>
        <span className="inline-flex items-center gap-1">
          <Icon icon={IconUser} size="xs" decorative />
          教員 ／
          <Icon icon={IconDoor} size="xs" decorative />
          教室の重複を検出します
        </span>
      </div>
    </div>
  );
}
